fn fibonacci(n: i64) -> u64 {
    let normalized = if n < 0 { 0 } else { n as u64 };
    let mut previous: u64 = 0;
    let mut current: u64 = 1;
    for _ in 0..normalized {
        let next = previous + current;
        previous = current;
        current = next;
    }
    previous
}

fn app(n: i64) -> String {
    fibonacci(n).to_string()
}
